class Solution(object):
    def isSumEqual(self, firstWord, secondWord, targetWord):
        def wordToNum(word):
            result = 0
            for char in word:
                result = result * 10 + (ord(char) - ord('a'))
            return result
        return wordToNum(firstWord) + wordToNum(secondWord) == wordToNum(targetWord)
